// ---------------------------------------------------------------------------

// Not a stable public API; the leading underscore signals "subject to change".
// At minimum the player-prompt composer is exposed so verification can exercise
// composition without a host.
export const _internal = {
  composePlayerPrompt,
  resolvePlayerId,
  effectiveBinding,
  DEFAULT_PLAYER_BINDING,
  adjudicate,
  buildJudgePrompt,
  extractRequiredFields,
  validateBossReplyOutput,
  parseJudgeJson,
  classifyBossText,
  buildClassifierPrompt,
  captainBridge,
  pendingBossQuestionFromContext,
  formatStateEntry,
  normalizeError,
  normalizeEventForTelemetry,
  CAPTAIN_STATES,
  INTERRUPT_TARGETS,
  RESUMABLE_STATE_IDS,
  QUIESCENT_STATE_IDS,
};

// ---------------------------------------------------------------------------
// Runtime factory (default export) — link.md §PlaybookRuntime contract
// ---------------------------------------------------------------------------

export function createPlaybookRuntime(
  options: LinkPlaybookOptions,
): PlaybookRuntime {
  // The deterministic player binding this runtime applies at every callPlayer
  // site — the baked default, with any per-run Captain override from options.
  const binding = effectiveBinding(options);

  let actor: ReturnType<typeof createActor> | undefined;
  let savedPorts: PlaybookPorts | undefined;
  // The Boss's per-turn AbortSignal, surfaced to the captain bridge so the port
  // calls see the right cancellation source. Undefined between turns.
  let activeSignal: AbortSignal | undefined;
  // A control-plane (adjudicator) fault captured during a turn, re-thrown out
  // of `handleBossInput` after the actor cleans up. Undefined when the turn had
  // none.
  let controlPlaneError: unknown;
  let hasControlPlaneError = false;
  // Previous root-machine state value, for the inspect-driven emitter.
  let priorState: unknown;

  // Emissions "shall be ordered, awaited, and never-dropped" (link.md
  // §PlaybookPorts contract). The inspect/subscribe callbacks are synchronous
  // and cannot await, so each emission is enqueued and a single drainer runs
  // them sequentially.
  const emitQueue: Array<() => Promise<void>> = [];
  let drainer: Promise<void> | undefined;
  let emissionError: unknown;
  let hasEmissionError = false;

  function enqueueEmit(fn: () => Promise<void>): void {
    emitQueue.push(fn);
    if (drainer === undefined) {
      drainer = (async () => {
        while (emitQueue.length > 0) {
          const next = emitQueue.shift();
          if (next === undefined) break;
          try {
            await next();
          } catch (error) {
            // Keep draining in order so later emissions are not dropped, then
            // surface the first host-side emission failure at the turn boundary.
            if (!hasEmissionError) emissionError = error;
            hasEmissionError = true;
          }
        }
        drainer = undefined;
      })();
    }
  }

  async function drainEmissions(): Promise<void> {
    await (drainer ?? Promise.resolve());
    if (hasEmissionError) {
      const error = emissionError;
      emissionError = undefined;
      hasEmissionError = false;
      throw error;
    }
  }

  // Construct the session-scoped actor: provide the concrete `captain` bridge,
  // derive FSM `input` from options, and subscribe (via inspect) to each root
  // snapshot so every transition surfaces telemetry and status before the next
  // event fires.
  function buildActor(ports: PlaybookPorts): ReturnType<typeof createActor> {
    priorState = undefined;
    return createActor(
      linkMachine.provide({
        actors: {
          captain: captainBridge(
            ports,
            binding,
            () => activeSignal,
            (error) => {
              if (!hasControlPlaneError) controlPlaneError = error;
              hasControlPlaneError = true;
            },
          ),
        },
      }),
      {
        input: options,
        inspect: (inspectionEvent) => {
          if (inspectionEvent.type !== '@xstate.snapshot') return;
          const snapshot = inspectionEvent.snapshot as {
            value?: unknown;
            context?: Record<string, unknown>;
          };
          // Only the root machine snapshot has a string value; ignore the
          // captain sub-actor's (fromPromise) snapshots.
          if (typeof snapshot.value !== 'string') return;
          const to = snapshot.value;
          if (priorState === to) return;
          const from = priorState;
          priorState = to;
          const context = snapshot.context ?? {};

          // One telemetry event per transition, under the namespaced topic
          // with payload { from, to, event } (event normalized so no raw Error
          // leaks). The runtime never interprets the topic.
          enqueueEmit(() =>
            ports.emitTelemetry({
              topic: 'playbook.fsm.state',
              payload: {
                from,
                to,
                event: normalizeEventForTelemetry(inspectionEvent.event),
              },
            }),
          );

          // One status per transition (the host filters). On entry to `failed`,
          // surface the actor's `lastError`.
          const line = formatStateEntry(to, context);
          if (to === 'failed') {
            const data = { lastError: normalizeError(context.lastError) };
            enqueueEmit(() => ports.emitStatus(line, data));
          } else {
            enqueueEmit(() => ports.emitStatus(line));
          }
        },
      },
    );
  }

  const runtime: PlaybookRuntime & { _getActor(): typeof actor } = {
    async init(ports: PlaybookPorts): Promise<void> {
      savedPorts = ports;
      actor = buildActor(ports);
      actor.start();
      await drainEmissions();
    },

    async handleBossInput(turn: {
      text: string;
      signal: AbortSignal;
    }): Promise<void> {
      if (actor === undefined || savedPorts === undefined) {
        throw new Error('handleBossInput: init must be called first');
      }
      const ports = savedPorts;
      activeSignal = turn.signal;
      controlPlaneError = undefined;
      hasControlPlaneError = false;
      try {
        // 1. Classify the turn into an FSM event through the Boss-event mapping.
        let event: LinkEvent | undefined;
        try {
          event = await classifyBossText(
            turn.text,
            ports,
            turn.signal,
            actor.getSnapshot(),
          );
        } catch (error) {
          // An abort during classification: no event was sent and the actor is
          // already quiescent, so exit the turn cleanly. Surface anything else.
          if (turn.signal.aborted) {
            await drainEmissions();
            return;
          }
          throw error;
        }
        if (turn.signal.aborted) {
          await drainEmissions();
          return;
        }
        // No event (empty text, no-action, or an unusable classifier reply):
        // drain any emissions and return.
        if (event === undefined) {
          await drainEmissions();
          return;
        }

        // 2. A `final` state is terminal and cannot accept new events: dispose
        //    and reconstruct the actor before sending.
        if (actor.getSnapshot().status === 'done') {
          actor.stop();
          actor = buildActor(ports);
          actor.start();
        }

        // 3. Send the classified event.
        actor.send(event);

        // 4. Drive to quiescence. Each captain invoke is completed by the
        //    bridge; on abort the natural-rejection path lands the machine in
        //    `failed`.
        await driveToQuiescence(actor);

        // Drain transition emissions so Boss sees this turn's final status.
        await drainEmissions();

        // A control-plane (adjudicator) fault is propagated out of the turn
        // after the actor's cleanup and the emission drain.
        if (hasControlPlaneError) {
          const error = controlPlaneError;
          controlPlaneError = undefined;
          hasControlPlaneError = false;
          throw error;
        }
      } finally {
        activeSignal = undefined;
      }
    },

    async dispose(): Promise<void> {
      if (actor !== undefined) {
        actor.stop();
        actor = undefined;
      }
      await drainEmissions();
      savedPorts = undefined;
    },

    // Test-only escape hatch for inspecting the underlying actor's snapshot.
    _getActor() {
      return actor;
    },
  };

  return runtime;
}

// The default export conforms to the shared generic factory type
// (link.md §PlaybookRuntime contract, §Output).
const _factoryConformance: PlaybookRuntimeFactory<LinkPlaybookOptions> =
  createPlaybookRuntime;
void _factoryConformance;

export default createPlaybookRuntime;
